// ---------- AUTH ----------
async function sha256(text) {
  const buf = new TextEncoder().encode(text);
  const hash = await crypto.subtle.digest('SHA-256', buf);
  return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2, '0')).join('');
}
async function unlock() {
  sessionStorage.setItem(SESSION_KEY, '1');
  document.getElementById('gate').style.display = 'none';
  document.getElementById('app').classList.add('unlocked');
  await loadActivations();
  loadViewState();
  renderGrid();
}
document.getElementById('gate-submit').addEventListener('click', async () => {
  const pw = document.getElementById('gate-pw').value;
  const err = document.getElementById('gate-error');
  if (await sha256(pw) === PW_HASH) {
    err.textContent = '';
    // Stash the verified password in sessionStorage so the proxy can authenticate API calls.
    // Cleared when the tab closes; never written to localStorage or disk.
    sessionStorage.setItem(PW_SESSION_KEY, pw);
    unlock();
  } else {
    err.textContent = 'Incorrect password';
  }
});
document.getElementById('gate-pw').addEventListener('keydown', e => {
  if (e.key === 'Enter') document.getElementById('gate-submit').click();
});
if (sessionStorage.getItem(SESSION_KEY) === '1') {
  // Returning user from a session unlocked before the proxy deploy may not have PW_SESSION_KEY set.
  // Force them to re-enter the password so we can populate it.
  if (!sessionStorage.getItem(PW_SESSION_KEY)) {
    sessionStorage.removeItem(SESSION_KEY);
  } else {
    unlock();
  }
}

